  1	import * as React from 'react';
  2	import { pluralize } from '@odf/core/components/utils';
  3	import { useGetInternalClusterDetails } from '@odf/core/redux/utils';
  4	import { GraphEmpty } from '@odf/shared/charts';
  5	import { DEFAULT_PROMETHEUS_RETENTION } from '@odf/shared/constants';
  6	import { PrometheusUtilizationItem } from '@odf/shared/dashboards';
  7	import {
  8	  dateTimeFormatterNoYear,
  9	  dateFormatterNoYear,
 10	} from '@odf/shared/details-page/datetime';
 11	import { FieldLevelHelp } from '@odf/shared/generic';
 12	import { DataUnavailableError } from '@odf/shared/generic/Error';
 13	import {
 14	  useCustomPrometheusPoll,
 15	  usePrometheusBasePath,
 16	} from '@odf/shared/hooks/custom-prometheus-poll';
 17	import { ConfigMapModel } from '@odf/shared/models';
 18	import { ConfigMapKind } from '@odf/shared/types';
 19	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 20	import { humanizeBinaryBytesWithNegatives, parser } from '@odf/shared/utils';
 21	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 22	import { TFunction } from 'react-i18next';
 23	import { Trans } from 'react-i18next';
 24	import {
 25	  Card,
 26	  CardBody,
 27	  CardHeader,
 28	  CardTitle,
 29	  Flex,
 30	  FlexItem,
 31	  PopoverPosition,
 32	  Text,
 33	  TextContent,
 34	  TextVariants,
 35	} from '@patternfly/react-core';
 36	import {
 37	  CAPACITY_TREND_QUERIES,
 38	  CEPH_CAPACITY_BREAKDOWN_QUERIES,
 39	  StorageDashboardQuery,
 40	} from '../../../queries/ceph-storage';
 41	
 42	const calculateDaysUp = (timespan: number): number | null => {
 43	  const daysPassed: number = timespan / (60 * 60 * 24);
 44	
 45	  // Rounding up to one decimal place if days passed is less than half a day
 46	  if (daysPassed < 0.5) {
 47	    return Math.ceil(daysPassed * 10) / 10; // Round up to one decimal place
 48	  }
 49	
 50	  return Math.ceil(daysPassed); // If days passed is half a day or more, round up to the nearest whole day
 51	};
 52	
 53	const understandingToolTip = (t: TFunction) => {
 54	  return (
 55	    <Trans t={t}>
 56	      <TextContent>
 57	        <Text component={TextVariants.h2}>Understand terms</Text>
 58	        <Text component={TextVariants.h4}>Net storage consumption</Text>
 59	
 60	        <Text component={TextVariants.p}>
 61	          Indicates the daily net change in storage capacity.
 62	        </Text>
 63	
 64	        <Text component={TextVariants.h4}>Average storage consumption </Text>
 65	
 66	        <Text component={TextVariants.p}>
 67	          Refers to the amount of data used over a specified period. A positive
 68	          average indicates how quickly the cluster is filling up, while a
 69	          negative average indicates the rate at which the cluster is clearing
 70	          up.
 71	        </Text>
 72	        <Text component={TextVariants.h4}>Estimated days until full ** </Text>
 73	
 74	        <Text component={TextVariants.p}>
 75	          Indicates the number of days remaining before a storage system reaches
 76	          its maximum capacity based on current usage trends.
 77	        </Text>
 78	
 79	        <Text component={TextVariants.small}>
 80	          Calculations for above metrics are based on the data gathered day to
 81	          day basis. **This is only a rough estimation These calculations are
 82	          based on the data gathered on day to day basis
 83	        </Text>
 84	      </TextContent>
 85	    </Trans>
 86	  );
 87	};
 88	
 89	const CapacityTrendCard: React.FC = () => {
 90	  const { t } = useCustomTranslation();
 91	
 92	  const { clusterName: ocsCluster } = useGetInternalClusterDetails();
 93	
 94	  const [configData, configLoaded, configLoadError] =
 95	    useK8sWatchResource<ConfigMapKind>({
 96	      kind: ConfigMapModel.kind,
 97	      namespace: 'openshift-monitoring',
 98	      name: 'cluster-monitoring-config',
 99	      isList: false,
100	    });
101	
102	  let retentionPeriod: string = DEFAULT_PROMETHEUS_RETENTION;
103	
104	  if (configLoaded && !configLoadError && configData?.data) {
105	    const retentionRegex =
106	      /retention:\s*["']?((\d+y)?(\d+w)?(\d+d)?(\d+h)?(\d+m)?(\d+s)?(\d+ms)?)["']?/;
107	    const retentionMatch =
108	      configData?.data?.['config.yaml']?.match(retentionRegex);
109	    if (!!retentionMatch && retentionMatch?.[1] !== '') {
110	      retentionPeriod = retentionMatch[1];
111	    } else {
112	      retentionPeriod = DEFAULT_PROMETHEUS_RETENTION;
113	    }
114	  }
115	
116	  const [availableCapacity, availableCapacityError, availableCapacityLoading] =
117	    useCustomPrometheusPoll({
118	      query:
119	        CAPACITY_TREND_QUERIES(ocsCluster)[
120	          StorageDashboardQuery.RAW_CAPACITY_AVAILABLE
121	        ],
122	      endpoint: 'api/v1/query' as any,
123	      basePath: usePrometheusBasePath(),
124	    });
125	
126	  const [totalUtil, totalUtilError, totalUtilLoading] = useCustomPrometheusPoll(
127	    {
128	      query: CAPACITY_TREND_QUERIES(ocsCluster, retentionPeriod)[
129	        StorageDashboardQuery.UTILIZATION_VECTOR
130	      ],
131	      endpoint: 'api/v1/query' as any,
132	      basePath: usePrometheusBasePath(),
133	    }
134	  );
135	  const [uptime, uptimeError, uptimeUtilLoading] = useCustomPrometheusPoll({
136	    query: CAPACITY_TREND_QUERIES(ocsCluster, retentionPeriod)[
137	      StorageDashboardQuery.UPTIME_DAYS
138	    ],
139	    endpoint: 'api/v1/query' as any,
140	    basePath: usePrometheusBasePath(),
141	  });
142	
143	  const [totalCapacity, totalCapacityError, totalCapacityLoading] =
144	    useCustomPrometheusPoll({
145	      query: CEPH_CAPACITY_BREAKDOWN_QUERIES(null, ocsCluster)[
146	        StorageDashboardQuery.CEPH_CAPACITY_TOTAL
147	      ],
148	      endpoint: 'api/v1/query' as any,
149	      basePath: usePrometheusBasePath(),
150	    });
151	
152	  const loadError =
153	    availableCapacityError ||
154	    totalUtilError ||
155	    uptimeError ||
156	    totalCapacityError;
157	  const loading =
158	    availableCapacityLoading ||
159	    totalUtilLoading ||
160	    uptimeUtilLoading ||
161	    totalCapacityLoading;
162	
163	  let daysUp: number;
164	  if (!loading && !loadError) {
165	    daysUp = calculateDaysUp(parser(uptime));
166	  }
167	
168	  const totalUtilMetric = parser(totalUtil);
169	  const totalCapacityMetric = parser(totalCapacity);
170	  const avgUtilMetric =
171	    !!daysUp && !!totalUtilMetric
172	      ? totalUtilMetric / Math.ceil(daysUp) // do a ceil function, if it's a new cluster (dayUp < 1)
173	      : 0;
174	
175	  const avgUtilMetricByte = humanizeBinaryBytesWithNegatives(
176	    avgUtilMetric.toFixed(0)
177	  );
178	  const availableCapacityMetric = parser(availableCapacity);
179	  let daysLeft =
180	    !!availableCapacityMetric && avgUtilMetric
181	      ? Math.floor(availableCapacityMetric / avgUtilMetric)
182	      : 0;
183	
184	  if (daysLeft < 0) {
185	    // Clean up negative average values, if a user empties a cluster the average value goes to negative we need to make
186	    // sure that estimated days left takes into account the average rate of filling up the cluster.
187	    // This will give better information about estimated days
188	    const clusterCleanUpToZeroDays =
189	      (totalCapacityMetric - availableCapacityMetric) / Math.abs(avgUtilMetric);
190	    const clusterFillUpToMaxDays =
191	      totalCapacityMetric / Math.abs(avgUtilMetric);
192	    daysLeft = Math.floor(clusterCleanUpToZeroDays + clusterFillUpToMaxDays);
193	  }
194	  return (
195	    <Card>
196	      <CardHeader>
197	        <CardTitle>{t('Consumption trend')}</CardTitle>
198	      </CardHeader>
199	      <CardBody>
200	        {!loading && !loadError && (
201	          <Flex direction={{ default: 'column' }}>
202	            <Flex>
203	              <FlexItem flex={{ default: 'flex_4' }}>
204	                <TextContent>
205	                  <Text component={TextVariants.h4}>
206	                    {t('Storage consumption')}
207	                  </Text>
208	                  <Text component={TextVariants.small}>
209	                    {t('Over the past {{daysUp}} ', {
210	                      daysUp: !!daysUp ? Math.ceil(daysUp) : null,
211	                    })}
212	                    {pluralize(Math.ceil(daysUp), t('day'), t('days'), false)}
213	                  </Text>
214	                </TextContent>
215	                <PrometheusUtilizationItem
216	                  title=""
217	                  description={t('Net storage consumption')}
218	                  utilizationQuery={
219	                    CAPACITY_TREND_QUERIES(ocsCluster)[
220	                      StorageDashboardQuery.UTILIZATION_1D
221	                    ]
222	                  }
223	                  humanizeValue={humanizeBinaryBytesWithNegatives}
224	                  hideHorizontalBorder={true}
225	                  hideCurrentHumanized={true}
226	                  formatDate={
227	                    daysUp >= 1
228	                      ? daysUp === 1
229	                        ? dateTimeFormatterNoYear.format
230	                        : dateFormatterNoYear.format
231	                      : undefined
232	                  }
233	                  chartType="grouped-line"
234	                  showLegend={true}
235	                  timespan={daysUp * 24 * 60 * 60 * 1000}
236	                  showHumanizedInLegend={true}
237	                />
238	              </FlexItem>
239	            </Flex>
240	            <Flex justifyContent={{ default: 'justifyContentSpaceBetween' }}>
241	              <FlexItem flex={{ default: 'flex_1' }}>
242	                <Text component={TextVariants.h4}>
243	                  {t('Average storage consumption')}
244	                </Text>
245	                {avgUtilMetricByte.string}
246	              </FlexItem>
247	              <FlexItem flex={{ default: 'flex_1' }}>
248	                <Text component={TextVariants.h4}>
249	                  {t('Estimated days until full')}
250	                </Text>
251	                {daysLeft} {pluralize(daysLeft, t('day'), t('days'), false)}
252	              </FlexItem>
253	            </Flex>
254	            <Flex>
255	              <FieldLevelHelp
256	                position={PopoverPosition.right}
257	                buttonText={t('Understanding these terms')}
258	                popoverHasAutoWidth
259	              >
260	                {understandingToolTip(t)}
261	              </FieldLevelHelp>
262	            </Flex>
263	          </Flex>
264	        )}
265	        {loading && !loadError && (
266	          <GraphEmpty loading={loading && !loadError} />
267	        )}
268	        {loadError && <DataUnavailableError />}
269	      </CardBody>
270	    </Card>
271	  );
272	};
273	
274	export default CapacityTrendCard;

